import os

app = Flask(__name__)

DATA_DIR = os.path.join(os.path.dirname(__file__), 'data')
TODO_FILE = os.path.join(DATA_DIR, 'todo.txt')

def _cm_success(action=None, message='', data=None):
    return jsonify({'ok': True, 'action': action, 'message': message, 'data': data, 'error': ''})

def _cm_failure(action=None, message='', data=None, error=''):
    return jsonify({'ok': False, 'action': action, 'message': message, 'data': data, 'error': error})

@app.route('/schema', methods=['GET'])
def schema():
    """Return the API schema."""
    return { "package": "todo", "endpoints": { "/add": {"args": ["item"], "returns": 'dict'}, "/list": {"args": [], "returns": 'dict'}, "/delete/<id>": {"args": ["id"], "returns": 'dict'}, }, "response_format": ['ok', 'action', 'message', 'data', 'error'], "storage_notes": "Uses a file for storage.", "notes": "API to manage todo items. Endpoints include add, list and delete.", }

@app.route('/add', methods=['POST'])
def add():
    """Add a new todo item."""
    data = request.get_json()
    if 'item' not in data:
        return _cm_failure(action='/add', message='Missing required field: item')

    with open(TODO_FILE, 'a') as f:
        f.write(f"{data['item']}\n")

    return _cm_success(action='/add', message='Item added successfully.')

@app.route('/list', methods=['GET'])
def list():
    """List all todo items."""
    with open(TODO_FILE, 'r') as f:
        items = [line.strip() for line in f]

    return _cm_success(action='/list', data=items)

@app.route('/delete/<id>', methods=['DELETE'])
def delete(id):
    """Delete a todo item by id."""
    with open(TODO_FILE, 'r') as f:
        items = [line.strip() for line in f]

    if int(id) >= len(items) or int(id) < 0:
        return _cm_failure(action='/delete', message='Invalid id.')

    del items[int(id)]

    with open(TODO_FILE, 'w') as f:
        for item in items:
            f.write(f"{item}\n")

    return _cm_success(action='/delete', message='Item deleted successfully.')

